mapper.select:
SELECT A.PROP_CD , A.PROP_NM , A.PROP_FEATURE , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = '00') AS CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , A.AREA_EXCLUSIVE , A.ROOM_CNT , A.FLOOR_NO , A.ADDRESS , A.BADGE_TYPE , CASE A.BADGE_TYPE WHEN 'RECOMMEND' THEN '추천' WHEN 'URGENT' THEN '급매' ELSE '-' END AS BADGE_TYPE_NM , A.SOLD_YN , CASE A.SOLD_YN WHEN 'Y' THEN '거래완료' ELSE '거래중' END AS SOLD_YN_NM , A.DISPLAY_YN , A.DISPLAY_START , A.DISPLAY_END , A.VIEW_CNT , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.CAT_CD = #{catCd}
AND A.SUB_CAT_CD = #{subCatCd}
AND A.DEAL_TYPE = #{dealType}
AND A.BADGE_TYPE = 'NONE' AND A.BADGE_TYPE = #{badgeType}
AND A.SOLD_YN = #{soldYn}
AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY A.RGT_DTM DESC

SELECT COUNT(*)
  FROM TB_PROPERTY A
 WHERE A.DEL_YN = 'N'
   AND A.USE_YN = 'Y'

   AND A.CAT_CD = #{catCd}


   AND A.SUB_CAT_CD = #{subCatCd}


   AND A.DEAL_TYPE = #{dealType}



       AND A.BADGE_TYPE = 'NONE'
       AND A.BADGE_TYPE = #{badgeType}



   AND A.SOLD_YN = #{soldYn}


   AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))

mapper.update:
UPDATE TB_PROPERTY
   SET DEL_YN = 'Y'
     , UPD_USR_CD = #{ssnUsrCd}
     , UPD_DTM = NOW()
 WHERE PROP_CD = #{propCd}

UPDATE TB_PROPERTY
   SET SOLD_YN    = #{soldYn}
     , UPD_USR_CD = #{ssnUsrCd}
     , UPD_DTM    = NOW()
 WHERE PROP_CD = #{propCd}
   AND DEL_YN = 'N'
